// ── General sub-panel ─────────────────────────────────────────────────────────

function GeneralSubPanel({ settings, s, actions, gallerySubTab }) {
    return (
        <div className="space-y-5">
            <SectionCard
                title="Gallery Type"
                description="Choose the overall gallery layout. Thumbnail Gallery shows images alongside a strip of clickable thumbnails. Anchor Navigation stacks all images vertically with dot navigation. Sticky Split shows a sticky main viewer alongside a vertically scrollable column of full-size images."
            >
                <SettingRow
                    label="Gallery Type"
                    description="Sets the primary display mode for the product gallery."
                    className="flex flex-col items-start gap-2 wpxs:flex-row wpxs:items-center wpxs:justify-between"
                >
                    <ButtonGroup
                        options={GALLERY_TYPES}
                        value={settings.galleryType}
                        className="grid grid-cols-2 wpsm:inline-flex wpsm:items-center"
                        onChange={(v) => {
                            s("galleryType", v);
                            if (v === "anchor") {
                                if (
                                    ["top", "bottom"].includes(
                                        settings.thumbnailPosition,
                                    )
                                ) {
                                    s("thumbnailPosition", "left");
                                }
                                // anchor only supports left/right position
                                if (
                                    !["left", "right"].includes(
                                        settings.mainImagePaginationPosition,
                                    )
                                ) {
                                    s("mainImagePaginationPosition", "left");
                                }
                                // anchor dots always require "dots" type
                                if (
                                    settings.mainImagePaginationType !== "dots"
                                ) {
                                    s("mainImagePaginationType", "dots");
                                }
                                if (gallerySubTab === "transition") {
                                    actions.setGallerySubTab("general");
                                }
                            }
                            if (v !== "anchor") {
                                // count/progressbar only support top/bottom; reset if leaving anchor with left/right
                                if (
                                    (settings.mainImagePaginationType ===
                                        "count" ||
                                        settings.mainImagePaginationType ===
                                            "progressbar") &&
                                    ["left", "right"].includes(
                                        settings.mainImagePaginationPosition,
                                    )
                                ) {
                                    s("mainImagePaginationPosition", "bottom");
                                }
                            }
                            if (v === "sticky-split") {
                                if (gallerySubTab === "transition") {
                                    actions.setGallerySubTab("general");
                                }
                            }
                            if (v === "hierarchy-grid") {
                                if (gallerySubTab === "transition") {
                                    actions.setGallerySubTab("general");
                                }
                            }
                            if (v === "tiles") {
                                if (
                                    ["transition", "thumbnails", "main-image", "navigation"].includes(
                                        gallerySubTab,
                                    )
                                ) {
                                    actions.setGallerySubTab("general");
                                }
                            }
                            if (v !== "tiles") {
                                // If switching away from tiles while on tiles sub-tab, go back to general
                                if (gallerySubTab === "tiles") {
                                    actions.setGallerySubTab("general");
                                }
                            }
                        }}
                    />
                </SettingRow>
            </SectionCard>
        </div>
    );
}

