// ── Navigation sub-panel ─────────────────────────────────────────────────────

function NavigationSubPanel({ settings, s, actions }) {
    // Write back a corrected position whenever galleryType or pagination type
    // makes the stored mainImagePaginationPosition invalid (e.g. "bottom" is
    // invalid for anchor; "left"/"right" are invalid for count/progressbar).
    useEffect(() => {
        if (!settings.mainImagePagination) return;
        const isTopBottomOnly =
            settings.mainImagePaginationType === "count" ||
            settings.mainImagePaginationType === "progressbar";
        const posOpts =
            settings.galleryType === "anchor"
                ? PAGINATION_POSITIONS.filter(
                      (p) => p.value === "left" || p.value === "right",
                  )
                : isTopBottomOnly
                ? PAGINATION_POSITIONS.filter(
                      (p) => p.value === "bottom" || p.value === "top",
                  )
                : PAGINATION_POSITIONS;
        const isValid = posOpts.some(
            (p) => p.value === settings.mainImagePaginationPosition,
        );
        if (!isValid && posOpts.length > 0) {
            s("mainImagePaginationPosition", posOpts[0].value);
        }
    }, [
        settings.galleryType,
        settings.mainImagePaginationType,
        settings.mainImagePagination,
        settings.mainImagePaginationPosition,
    ]);

    return (
        <div className="space-y-5">
            <SectionCard
                title="Main Image Navigation"
                description="Arrows, pagination, and lightbox button controls for the main product image."
            >
                {settings.galleryType === "sticky-split" &&
                    (settings.mainImageArrows ||
                        settings.mainImagePagination) && (
                        <InfoBox variant="tip">
                            With <strong>Sticky Split</strong>, the scroll
                            column acts as the primary navigation. It is
                            recommended to keep{" "}
                            <strong>Navigation Arrows</strong> and{" "}
                            <strong>Pagination</strong> disabled.
                        </InfoBox>
                    )}

                {settings.galleryType !== "anchor" && (
                    <>
                        <SettingRow
                            label="Navigation Arrows"
                            description="Show previous/next arrow buttons on the main image. Syncs with the thumbnail strip."
                        >
                            <Toggle
                                value={settings.mainImageArrows}
                                onChange={(v) => s("mainImageArrows", v)}
                            />
                        </SettingRow>

                        {settings.mainImageArrows && (
                            <SettingRow
                                label="Auto-hide Arrows"
                                description="Hide arrows when the cursor leaves the image. Turn off to keep them always visible."
                            >
                                <Toggle
                                    value={settings.mainImageArrowsAutoHide}
                                    onChange={(v) =>
                                        s("mainImageArrowsAutoHide", v)
                                    }
                                />
                            </SettingRow>
                        )}

                        <SettingRow
                            label="Pagination"
                            description="Show a pagination indicator dots for the main image for quick navigation."
                        >
                            <Toggle
                                value={settings.mainImagePagination}
                                onChange={(v) => s("mainImagePagination", v)}
                            />
                        </SettingRow>

                        {settings.mainImagePagination && (
                            <SettingRow
                                label="Pagination Style"
                                description="Dots are clickable indicators. Progress Bar shows a thin fill line that advances with each image. Count shows a numeric counter (e.g. 2 / 8) with arrow buttons to navigate."
                            >
                                <ButtonGroup
                                    options={PAGINATION_TYPES}
                                    value={settings.mainImagePaginationType}
                                    onChange={(v) => {
                                        s("mainImagePaginationType", v);
                                        if (
                                            (v === "count" ||
                                                v === "progressbar") &&
                                            ["left", "right"].includes(
                                                settings.mainImagePaginationPosition,
                                            )
                                        ) {
                                            s(
                                                "mainImagePaginationPosition",
                                                "bottom",
                                            );
                                        }
                                    }}
                                />
                            </SettingRow>
                        )}
                    </>
                )}

                {/* Anchor nav: dot position is always relevant — the frontend
                    renders the dot rail unconditionally, so show this control
                    regardless of the mainImagePagination toggle. */}
                {settings.galleryType === "anchor" && (
                    <SettingRow
                        label="Dot Position"
                        description="Which side the scroll-linked navigation dots appear on."
                    >
                        <ButtonGroup
                            options={PAGINATION_POSITIONS.filter(
                                (p) =>
                                    p.value === "left" || p.value === "right",
                            )}
                            value={
                                ["left", "right"].includes(
                                    settings.mainImagePaginationPosition,
                                )
                                    ? settings.mainImagePaginationPosition
                                    : "left"
                            }
                            onChange={(v) =>
                                s("mainImagePaginationPosition", v)
                            }
                        />
                    </SettingRow>
                )}

                {/* Non-anchor: position only matters when pagination is on. */}
                {settings.mainImagePagination &&
                    settings.galleryType !== "anchor" &&
                    (() => {
                        const isTopBottomOnly =
                            settings.mainImagePaginationType === "count" ||
                            settings.mainImagePaginationType === "progressbar";
                        const posOpts = isTopBottomOnly
                            ? PAGINATION_POSITIONS.filter(
                                  (p) =>
                                      p.value === "bottom" || p.value === "top",
                              )
                            : PAGINATION_POSITIONS;
                        const safePos = posOpts.some(
                            (p) =>
                                p.value ===
                                settings.mainImagePaginationPosition,
                        )
                            ? settings.mainImagePaginationPosition
                            : posOpts[0]?.value;
                        return (
                            <SettingRow
                                label="Pagination Position"
                                description="Where the pagination appears. Progress Bar and Count support Top or Bottom only."
                            >
                                <ButtonGroup
                                    options={posOpts}
                                    value={safePos}
                                    onChange={(v) =>
                                        s("mainImagePaginationPosition", v)
                                    }
                                />
                            </SettingRow>
                        );
                    })()}

                {settings.mainImagePagination &&
                    settings.galleryType !== "anchor" && (
                        <SettingRow
                            label="Auto-hide"
                            description="Hide the pagination when the cursor leaves the image. Turn off to keep it always visible."
                        >
                            <Toggle
                                value={settings.mainImagePaginationAutoHide}
                                onChange={(v) =>
                                    s("mainImagePaginationAutoHide", v)
                                }
                            />
                        </SettingRow>
                    )}

                {(settings.galleryType === "thumbnail" ||
                    settings.galleryType === "sticky-split") &&
                    !settings.zoomOnHover &&
                    !settings.touchZoom && (
                        <SettingRow
                            label="Swipe / Drag Navigation"
                            description="Drag or swipe the main image to navigate between gallery items. Works on both desktop (mouse drag) and mobile (touch swipe). Only available when Zoom on Hover and Touch Zoom are both disabled."
                        >
                            <Toggle
                                value={settings.mainImageSwipe}
                                onChange={(v) => s("mainImageSwipe", v)}
                            />
                        </SettingRow>
                    )}

                {settings.galleryType === "thumbnail" && (
                    <SettingRow
                        label="Scroll Navigation"
                        description="Use the mouse scroll wheel to navigate between gallery images. Scrolling in either direction moves to the next or previous image."
                    >
                        <Toggle
                            value={settings.mainImageScrollNav}
                            onChange={(v) => s("mainImageScrollNav", v)}
                        />
                    </SettingRow>
                )}

                {settings.galleryType === "thumbnail" &&
                    settings.mainImageScrollNav &&
                    settings.zoomOnHover && (
                        <InfoBox variant="tip">
                            <strong>Note:</strong> Scroll Navigation works best
                            when{" "}
                            <strong>
                                <button
                                    type="button"
                                    onClick={() => actions.setTab("zoom")}
                                >
                                    Zoom on Hover
                                </button>
                            </strong>{" "}
                            is disabled — enabling both features at the same
                            time could cause interference.
                        </InfoBox>
                    )}

                {settings.galleryType === "thumbnail" &&
                    settings.mainImageScrollNav && (
                        <SettingRow
                            label="Scroll Response Speed"
                            description="Minimum time between scroll-triggered navigations. Higher values slow down how fast scrolling moves through images."
                        >
                            <NumberInput
                                value={settings.mainImageScrollNavDelay ?? 500}
                                onChange={(v) =>
                                    s("mainImageScrollNavDelay", v)
                                }
                                min={100}
                                max={2000}
                                unit="ms"
                                width="w-24"
                            />
                        </SettingRow>
                    )}

                {settings.lightbox && settings.lightboxOnClick && (
                    <SettingRow
                        label="Auto-hide Expand Button"
                        description="Hide the lightbox expand button when the cursor leaves the image. Turn off to keep it always visible."
                    >
                        <Toggle
                            value={settings.lightboxButtonAutoHide}
                            onChange={(v) => s("lightboxButtonAutoHide", v)}
                        />
                    </SettingRow>
                )}
            </SectionCard>
        </div>
    );
}

